{
  "name": "GeoGuide AI",
  "description": "An interactive map-based chatbot powered by Gemini, featuring real-time Google Maps grounding, Web Search, and advanced reasoning.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  MAPS = 'MAPS',
  SEARCH = 'SEARCH',
  CHAT = 'CHAT',
}

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isError?: boolean;
  groundingMetadata?: GroundingMetadata;
}

export interface GroundingMetadata {
  searchChunks?: SearchChunk[];
  mapChunks?: MapChunk[];
}

export interface SearchChunk {
  web: {
    uri: string;
    title: string;
  };
}

export interface MapChunk {
  maps: {
    source: {
      uri: string;
    };
    title: string;
    placeAnswerSources?: {
      reviewSnippets?: {
        snippet: string;
        author: string;
      }[];
    }[];
  };
}

export interface AppState {
  messages: ChatMessage[];
  isLoading: boolean;
  userLocation: Coordinates | null;
  mapCenter: Coordinates;
  mode: AppMode;
  apiKey: string | null;
}

import { AppMode, Coordinates } from './types';

export const DEFAULT_CENTER: Coordinates = {
  lat: 37.7749, // San Francisco
  lng: -122.4194,
};

export const MODES = [
  {
    id: AppMode.MAPS,
    label: 'Maps',
    description: 'Find places nearby (Gemini 2.5)',
    icon: 'Map',
  },
  {
    id: AppMode.SEARCH,
    label: 'Search',
    description: 'Web knowledge (Gemini 3 Flash)',
    icon: 'Globe',
  },
  {
    id: AppMode.CHAT,
    label: 'Chat',
    description: 'Complex reasoning (Gemini 3 Pro)',
    icon: 'MessageSquare',
  },
];

export const SYSTEM_INSTRUCTIONS = {
  [AppMode.MAPS]: "You are a helpful location expert. Use the Google Maps tool to find real-world places. Always provide the names and addresses if available. Be concise and practical.",
  [AppMode.SEARCH]: "You are a knowledgeable research assistant. Use Google Search to find the latest information. Summarize findings clearly.",
  [AppMode.CHAT]: "You are a friendly and intelligent AI assistant. Engage in helpful conversation and answer questions with depth and clarity.",
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { AppMode, Coordinates, ChatMessage, GroundingMetadata } from "../types";
import { SYSTEM_INSTRUCTIONS } from "../constants";

let genAI: GoogleGenAI | null = null;

export const initializeGenAI = (apiKey: string) => {
  genAI = new GoogleGenAI({ apiKey });
};

export const sendMessageToGemini = async (
  prompt: string,
  mode: AppMode,
  history: ChatMessage[],
  location?: Coordinates
): Promise<ChatMessage> => {
  if (!genAI) {
    throw new Error("Gemini API not initialized");
  }

  let modelName = 'gemini-3-pro-preview';
  const tools: any[] = [];
  const toolConfig: any = {};

  // Configure Model and Tools based on Mode
  switch (mode) {
    case AppMode.MAPS:
      modelName = 'gemini-2.5-flash'; // Required for Maps Grounding
      tools.push({ googleMaps: {} });
      if (location) {
        toolConfig.retrievalConfig = {
          latLng: {
            latitude: location.lat,
            longitude: location.lng,
          },
        };
      }
      break;

    case AppMode.SEARCH:
      modelName = 'gemini-3-flash-preview';
      tools.push({ googleSearch: {} });
      break;

    case AppMode.CHAT:
      modelName = 'gemini-3-pro-preview';
      break;
  }

  try {
    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTIONS[mode],
    };

    if (tools.length > 0) {
      config.tools = tools;
    }

    if (Object.keys(toolConfig).length > 0) {
      config.toolConfig = toolConfig;
    }

    const contents = history
      .filter(m => !m.isError)
      .map(m => ({
        role: m.role,
        parts: [{ text: m.text }],
      }));

    // Add current message
    contents.push({
      role: 'user',
      parts: [{ text: prompt }],
    });

    const response: GenerateContentResponse = await genAI.models.generateContent({
      model: modelName,
      contents: contents,
      config: config,
    });

    const text = response.text || "I couldn't generate a text response.";

    // Extract Grounding Metadata
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const groundingMetadata: GroundingMetadata = {};

    if (groundingChunks) {
      groundingMetadata.mapChunks = groundingChunks
        .filter((c: any) => c.maps)
        .map((c: any) => c as any); // Type assertion for simplicity in this demo context

      groundingMetadata.searchChunks = groundingChunks
        .filter((c: any) => c.web)
        .map((c: any) => c as any);
    }

    return {
      id: Date.now().toString(),
      role: 'model',
      text: text,
      timestamp: new Date(),
      groundingMetadata,
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return {
      id: Date.now().toString(),
      role: 'model',
      text: `Error: ${error.message || "Something went wrong."}`,
      timestamp: new Date(),
      isError: true,
    };
  }
};

import React from 'react';
import ReactMarkdown from 'react-markdown';

interface MarkdownRendererProps {
  content: string;
}

export const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
  return (
    <div className="prose prose-sm prose-slate dark:prose-invert max-w-none">
      <ReactMarkdown
        components={{
          a: ({ node, ...props }) => (
            <a
              {...props}
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 dark:text-blue-400 hover:underline"
