import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates } from '../types';

// Fix Leaflet default icon issue
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
  iconUrl: icon,
  shadowUrl: iconShadow,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

L.Marker.prototype.options.icon = DefaultIcon;

interface MapComponentProps {
  center: Coordinates;
  userLocation: Coordinates | null;
  onCenterChange: (center: Coordinates) => void;
}

// Component to handle map movement events
const MapEvents: React.FC<{ onCenterChange: (c: Coordinates) => void }> = ({ onCenterChange }) => {
  const map = useMapEvents({
    moveend: () => {
      const center = map.getCenter();
      onCenterChange({ lat: center.lat, lng: center.lng });
    },
  });
  return null;
};

// Component to update view when center prop changes programmatically
const MapUpdater: React.FC<{ center: Coordinates }> = ({ center }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo([center.lat, center.lng], map.getZoom());
  }, [center, map]);
  return null;
};

export const MapComponent: React.FC<MapComponentProps> = ({ center, userLocation, onCenterChange }) => {
  // Use a unique key to force re-render if needed, but here we manage updates via MapUpdater
  return (
    <MapContainer
      center={[center.lat, center.lng]}
      zoom={13}
      scrollWheelZoom={true}
      className="w-full h-full"
      zoomControl={false} // We will add custom controls if needed or rely on default
    >
      <TileLayer
        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      {userLocation && (
        <Marker position={[userLocation.lat, userLocation.lng]}>
          <Popup>You are here</Popup>
        </Marker>
      )}

      <MapEvents onCenterChange={onCenterChange} />
      <MapUpdater center={center} />
    </MapContainer>
  );
};

import React, { useRef, useEffect } from 'react';
import { Send, Map, Globe, MessageSquare, Loader2, MapPin, ExternalLink } from 'lucide-react';
import { ChatMessage, AppMode, GroundingMetadata } from '../types';
import { MODES } from '../constants';
import { MarkdownRenderer } from './MarkdownRenderer';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  isLoading: boolean;
  currentMode: AppMode;
  onSend: (text: string) => void;
  onModeChange: (mode: AppMode) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({
  messages,
  isLoading,
  currentMode,
  onSend,
  onModeChange,
}) => {
  const [input, setInput] = React.useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isLoading) {
      onSend(input);
      setInput('');
    }
  };

  const renderSources = (metadata?: GroundingMetadata) => {
    if (!metadata) return null;

    const { mapChunks, searchChunks } = metadata;
    const hasMaps = mapChunks && mapChunks.length > 0;
    const hasSearch = searchChunks && searchChunks.length > 0;

    if (!hasMaps && !hasSearch) return null;

    return (
      <div className="mt-3 pt-3 border-t border-gray-200 dark:border-gray-700 text-xs">
        <p className="font-semibold text-gray-500 mb-2 uppercase tracking-wider">Sources</p>
        <div className="flex flex-wrap gap-2">
          {hasMaps && mapChunks.map((chunk, idx) => (
            <a
              key={`map-${idx}`}
              href={chunk.maps.source.uri}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-300 px-2 py-1 rounded border border-green-200 dark:border-green-800 hover:bg-green-100 dark:hover:bg-green-900/50 transition-colors"
            >
              <MapPin className="w-3 h-3" />
              <span className="truncate max-w-[150px]">{chunk.maps.title}</span>
            </a>
          ))}
          {hasSearch && searchChunks.map((chunk, idx) => (
            <a
              key={`search-${idx}`}
              href={chunk.web.uri}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 px-2 py-1 rounded border border-blue-200 dark:border-blue-800 hover:bg-blue-100 dark:hover:bg-blue-900/50 transition-colors"
            >
              <ExternalLink className="w-3 h-3" />
              <span className="truncate max-w-[150px]">{chunk.web.title}</span>
            </a>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-white dark:bg-slate-900 shadow-xl rounded-xl overflow-hidden border border-gray-200 dark:border-gray-800">
      {/* Header / Mode Selector */}
      <div className="bg-slate-50 dark:bg-slate-950 p-2 border-b border-gray-200 dark:border-gray-800">
        <div className="flex gap-1 justify-between bg-gray-200 dark:bg-slate-800 p-1 rounded-lg">
          {MODES.map((mode) => {
            const Icon = mode.icon === 'Map' ? Map : mode.icon === 'Globe' ? Globe : MessageSquare;
            const isActive = currentMode === mode.id;
            return (
              <button
                key={mode.id}
                onClick={() => onModeChange(mode.id)}
                className={`flex-1 flex items-center justify-center gap-2 py-2 px-3 rounded-md text-sm font-medium transition-all duration-200 ${
                  isActive
                    ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm'
                    : 'text-gray-500 dark:text-gray-400 hover:bg-gray-300/50 dark:hover:bg-slate-700/50'
                }`}
                title={mode.description}
              >
                <Icon size={16} />
                <span className="hidden sm:inline">{mode.label}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 dark:bg-slate-900/50">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 text-center p-8 opacity-60">
            <div className="bg-blue-100 dark:bg-slate-800 p-4 rounded-full mb-4">
               <Map className="w-8 h-8 text-blue-500" />
            </div>
            <p className="text-lg font-medium text-gray-600 dark:text-gray-300">GeoGuide AI</p>
            <p className="text-sm">Ask about places, check web info, or chat.</p>
          </div>
        )}

        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl px-4 py-3 shadow-sm ${
                msg.role === 'user'
                  ? 'bg-blue-600 text-white rounded-br-none'
                  : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-bl-none border border-gray-100 dark:border-gray-700'
              }`}
            >
              <MarkdownRenderer content={msg.text} />
              {msg.role === 'model' && renderSources(msg.groundingMetadata)}
              <div
                className={`text-[10px] mt-1 text-right opacity-70 ${
                  msg.role === 'user' ? 'text-blue-100' : 'text-gray-400'
                }`}
              >
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white dark:bg-slate-800 rounded-2xl rounded-bl-none px-4 py-3 border border-gray-100 dark:border-gray-700 flex items-center gap-2">
              <Loader2 className="w-4 h-4 animate-spin text-blue-500" />
              <span className="text-sm text-gray-500">Thinking...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <form onSubmit={handleSubmit} className="p-4 bg-white dark:bg-slate-950 border-t border-gray-200 dark:border-gray-800">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={`Ask about ${currentMode === AppMode.MAPS ? 'places nearby' : currentMode === AppMode.SEARCH ? 'events & news' : 'anything'}...`}
            className="w-full pl-4 pr-12 py-3 bg-gray-100 dark:bg-slate-900 border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-slate-800 focus:ring-2 focus:ring-blue-200 dark:focus:ring-blue-900/30 rounded-xl text-slate-900 dark:text-white placeholder-gray-400 transition-all outline-none"
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="absolute right-2 p-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, ChatMessage, Coordinates } from './types';
import { DEFAULT_CENTER } from './constants';
import { initializeGenAI, sendMessageToGemini } from './services/geminiService';
import { MapComponent } from './components/MapComponent';
import { ChatInterface } from './components/ChatInterface';
import { Menu, X } from 'lucide-react';

const App: React.FC = () => {
  const [apiKey, setApiKey] = useState<string | null>(process.env.API_KEY || null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.MAPS);

  // Map State
  const [userLocation, setUserLocation] = useState<Coordinates | null>(null);
  const [mapCenter, setMapCenter] = useState<Coordinates>(DEFAULT_CENTER);

  // UI State
  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);

  // Initialize API
  useEffect(() => {
    if (apiKey) {
      initializeGenAI(apiKey);
    }
  }, [apiKey]);

  // Geolocation
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const coords = { lat: latitude, lng: longitude };
          setUserLocation(coords);
          setMapCenter(coords);
        },
        (error) => {
          console.warn("Geolocation denied or failed:", error);
        }
      );
    }
  }, []);

  const handleSendMessage = useCallback(async (text: string) => {
    if (!apiKey) return;

    // Optimistically add user message
    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    // Pass the *current* map center as the context location for the query
    // This allows users to pan to a city and ask "What's good to eat here?"
    const contextLocation = mapCenter;

    const response = await sendMessageToGemini(
      text,
      currentMode,
      messages, // Use current state messages for history
      contextLocation
    );

    setMessages(prev => [...prev, response]);
    setIsLoading(false);
  }, [apiKey, currentMode, messages, mapCenter]);

  // If no API key is present (shouldn't happen in this environment as per instructions, but safe to handle visually if needed)
  if (!apiKey) {
    return (
      <div className="flex h-screen items-center justify-center bg-slate-100 dark:bg-slate-900 text-slate-800 dark:text-slate-200">
        <p>API Key not found in environment.</p>
      </div>
    );
  }

  return (
    <div className="relative h-screen w-screen overflow-hidden bg-slate-100 dark:bg-slate-900 flex flex-col md:flex-row">

      {/* Mobile Header / Toggle */}
      <div className="md:hidden absolute top-0 left-0 right-0 z-[1000] p-4 pointer-events-none flex justify-end">
         <button
          onClick={() => setIsMobileChatOpen(!isMobileChatOpen)}
          className="pointer-events-auto bg-white dark:bg-slate-800 p-3 rounded-full shadow-lg border border-gray-200 dark:border-gray-700 text-blue-600 dark:text-blue-400"
        >
          {isMobileChatOpen ? <X size={24} /> : <MessageSquareIcon />}
        </button>
      </div>

      {/* Map Section */}
      <div className="w-full h-full md:w-2/3 lg:w-3/4 absolute md:relative z-0">
        <MapComponent 
          center={mapCenter} 
          userLocation={userLocation} 
          onCenterChange={setMapCenter}
        />

        {/* Map Overlay Info */}
        <div className="absolute top-4 left-4 z-[400] bg-white/90 dark:bg-slate-900/90 backdrop-blur-sm p-3 rounded-lg shadow-md border border-gray-200 dark:border-gray-700 max-w-xs">
           <h1 className="font-bold text-slate-800 dark:text-slate-100 text-lg flex items-center gap-2">
             <span className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></span>
             GeoGuide AI
           </h1>
           <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">
             Pan map to update context area.
           </p>
           <div className="text-[10px] font-mono mt-1 text-slate-400">
             {mapCenter.lat.toFixed(4)}, {mapCenter.lng.toFixed(4)}
           </div>
        </div>
      </div>

      {/* Chat Section */}
      <div 
        className={`
          absolute md:relative z-[500] 
          w-full md:w-1/3 lg:w-1/4 h-[85vh] md:h-full bottom-0 
          transition-transform duration-300 ease-in-out
          ${isMobileChatOpen ? 'translate-y-0' : 'translate-y-[calc(100%-80px)]'}
          md:translate-y-0
          bg-transparent pointer-events-none md:pointer-events-auto
          flex flex-col justify-end md:justify-start
        `}
      >
        <div className="h-full pointer-events-auto p-4 md:p-0 md:border-l border-gray-200 dark:border-gray-800 bg-transparent md:bg-white md:dark:bg-slate-900">
          <ChatInterface
            messages={messages}
            isLoading={isLoading}
            currentMode={currentMode}
            onSend={handleSendMessage}
            onModeChange={setCurrentMode}
          />
        </div>
      </div>
    </div>
  );
};

const MessageSquareIcon = () => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width="24"
    height="24"
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
  </svg>
);

export default App;

import React, { useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates } from '../types';

// Fix Leaflet default icon issue using CDN links instead of local imports
const iconUrl = 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png';
const iconShadow = 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
  iconUrl: iconUrl,
  shadowUrl: iconShadow,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
});

L.Marker.prototype.options.icon = DefaultIcon;

interface MapComponentProps {
  center: Coordinates;
  userLocation: Coordinates | null;
  onCenterChange: (center: Coordinates) => void;
}

// Component to handle map movement events
const MapEvents: React.FC<{ onCenterChange: (c: Coordinates) => void }> = ({ onCenterChange }) => {
  const map = useMapEvents({
    moveend: () => {
      const center = map.getCenter();
      onCenterChange({ lat: center.lat, lng: center.lng });
    },
  });
  return null;
};

// Component to update view when center prop changes programmatically
const MapUpdater: React.FC<{ center: Coordinates }> = ({ center }) => {
  const map = useMap();

  useEffect(() => {
    const current = map.getCenter();
    // Calculate distance to avoid infinite loops of flyTo -> moveend -> setCenter -> flyTo
    const diffLat = Math.abs(current.lat - center.lat);
    const diffLng = Math.abs(current.lng - center.lng);

    // Only fly if the difference is significant (e.g., > 0.0001 degrees)
    if (diffLat > 0.0001 || diffLng > 0.0001) {
      map.flyTo([center.lat, center.lng], map.getZoom());
    }
  }, [center.lat, center.lng, map]);

  return null;
};

export const MapComponent: React.FC<MapComponentProps> = ({ center, userLocation, onCenterChange }) => {
  return (
    <MapContainer
      center={[center.lat, center.lng]}
      zoom={13}
      scrollWheelZoom={true}
      className="w-full h-full"
      zoomControl={false}
    >
      <TileLayer
        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      {userLocation && (
        <Marker position={[userLocation.lat, userLocation.lng]}>
          <Popup>You are here</Popup>
        </Marker>
      )}

      <MapEvents onCenterChange={onCenterChange} />
